function LxPreloadRes:LxPreloadRes()
    ---@type LxResRequester[]
    self._resRequesterList = {}

    self._isEnterGameProLoad = false
    self._isLoginProLoad = false

    ---@type LxPreloadTask
    self._enterGamePreloadTask = nil

    ---@type LxPreloadTask
    self._loginPreloadTask = nil

    ---@type LxPreloadTask
    self._mainPreloadTask = nil
end

function LxPreloadRes:Dispose()
    if self._isDisposed then return end

    if self._mainPreloadTask then
        self._mainPreloadTask:Dispose()
        self._mainPreloadTask = nil
    end

    if self._loginPreloadTask then
        self._loginPreloadTask:Dispose()
        self._loginPreloadTask = nil
    end

    if self._enterGamePreloadTask then
        self._enterGamePreloadTask:Dispose()
        self._enterGamePreloadTask = nil
    end

    for k,v in ipairs(self._resRequesterList) do
        v:Dispose()
    end
    self._resRequesterList = nil

    self._isDisposed = true
end

function LxPreloadRes:AddResRequester(requester)
    table.insert(self._resRequesterList, requester)
end

---region 启动时预加载的Bundle
function LxPreloadRes:EnterMainPreload(excOk, actionObj)
    ---@type LxPreloadTask
    local ctrl = self._mainPreloadTask
    if not ctrl then
        ctrl = require("LApp.component.task.LxPreloadTask"):New()
        ctrl:Initialize()
        self._mainPreloadTask = ctrl
    end

    ctrl:InitPreload(excOk, nil, actionObj)

    ctrl:AddLoadAllAssets("Shader/Custom_UI-Default-Gray.shader", typeofShader)
    ctrl:AddLoadAllAssets("Font/ArtFont/default/default_emoji.asset" ,nil)
    ctrl:AddLoadAllAssets("Font/SysFont/default/OPPOSansRMixB.asset", nil)

    local lngAssets = self:_GetLngAssets()
    if lngAssets and #lngAssets > 0 then
        for k,assetName in ipairs(lngAssets) do
            ctrl:AddLoadAllAssets(assetName, nil)
        end
    end
    ctrl:StartPreload()
end
---endregion 启动时预加载的Bundle

---region 登录界面的预加载的Bundle
function LxPreloadRes:EnterLoginPreload(excOk, cbProcess, actionObj)
    if self._isLoginProLoad then
        excOk(actionObj)
        return
    end

    self._isLoginProLoad = true
    ---@type LxPreloadTask
    local ctrl = self._loginPreloadTask
    if not ctrl then
        ctrl = require("LApp.component.task.LxPreloadTask"):New()
        ctrl:Initialize()
        self._loginPreloadTask = ctrl
    end
    ctrl:InitPreload(excOk, cbProcess, actionObj)
    self:DealPreLoadList(ctrl)
    ctrl:StartPreload()
end

