function LxPreloadRes:EnterGamePreload(excOk, cbProcess, actionObj)
    if self._isEnterGameProLoad then
        excOk(actionObj)
        return
    end
    self._isEnterGameProLoad = true
    ---@type LxPreloadTask
    local ctrl = self._enterGamePreloadTask
    if not ctrl then
        ctrl = require("LApp.component.task.LxPreloadTask"):New()
        ctrl:Initialize()
        self._enterGamePreloadTask = ctrl
    end

    ctrl:InitPreload(excOk, cbProcess, actionObj)

    if LGameSettings.isLoginAfter then
         self:DealPreLoadList(ctrl)
    end

    --ctrl:AddLoadSubAssets("UI/Atlas/IconItem", typeofSprite)

    ctrl:StartPreload()
end

function LxPreloadRes:DealPreLoadList(ctrl)
    if CS.IsWebGL() then
        self:_InternalWebGLLoginPreLoad(ctrl)
    else
        self:_InternalNormalLoginPreLoad(ctrl)
    end
end

---end region 进入游戏场景预加载的Bundle

