---region post shader 初始化
function LxPreloadRes:LoadPostShaders(excOk, singleOk)
    local shaders = {
        "Shader/Custom_PostProcess-Average.shader",
        "Shader/Custom_PostProcess-AverageBlur.shader",
        "Shader/Custom_PostProcess-Clear.shader",
        "Shader/Custom_PostProcess-Cover.shader",
        "Shader/Custom_PostProcess-Gray.shader",
        "Shader/Custom_PostProcess-GrayUI.shader",
        "Shader/Custom_PostProcess-MotionBlur.shader",
        "Shader/Custom_PostProcess-SimpleBlur.shader",
        "Shader/Custom_PostProcess_Rain.shader"
    }
    local requestList = {}
    local len = #shaders
    local curLen = 0
    local loadedOk = function(obj)
        singleOk(obj)
        curLen = curLen + 1
        if curLen == len then
            excOk()
        end
    end
    for k,v in ipairs(shaders) do
        local requester = LxResUtil.GetAssetRequester(v, typeofShader, loadedOk)
        self:AddResRequester(requester)
        table.insert(requestList, requester)
    end
    for k,v in ipairs(requestList) do
        v:StartRequester()
    end
end

---endregion post shader 初始化

